import React, { useState } from "react";
import { Outlet, NavLink, useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import { HomeIcon, UsersIcon, BriefcaseIcon, BanknotesIcon, CalendarDaysIcon, ChartBarIcon, SparklesIcon, Cog6ToothIcon, ArrowRightOnRectangleIcon, UserCircleIcon, Bars3Icon, TrophyIcon, BellIcon } from "@heroicons/react/24/outline";
import { SparklesIcon as SparklesSolid } from "@heroicons/react/24/solid";
import clsx from "clsx";

const navItems = [
  { to: "/dashboard",    icon: HomeIcon,         label: "Dashboard" },
  { to: "/employees",    icon: UsersIcon,         label: "Employees" },
  { to: "/recruitment",  icon: BriefcaseIcon,     label: "Recruitment" },
  { to: "/payroll",      icon: BanknotesIcon,     label: "Payroll" },
  { to: "/leave",        icon: CalendarDaysIcon,  label: "Leave" },
  { to: "/performance",  icon: TrophyIcon,        label: "Performance" },
  { to: "/analytics",    icon: ChartBarIcon,      label: "Analytics" },
  { to: "/ai-assistant", icon: SparklesIcon,      label: "AI Assistant", highlight: true },
];

export default function Layout() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const handleLogout = async () => { await logout(); navigate("/login"); };

  const SidebarContent = () => (
    <aside className="flex flex-col bg-white border-r border-slate-200 h-full w-64">
      <div className="flex items-center gap-2.5 px-4 py-5 border-b border-slate-100">
        <div className="w-8 h-8 bg-gradient-to-br from-primary-500 to-purple-600 rounded-lg flex items-center justify-center">
          <SparklesSolid className="w-4 h-4 text-white" />
        </div>
        <div>
          <p className="font-bold text-slate-900 text-sm">AI-HRM</p>
          <p className="text-xs text-slate-400">Smart HR Platform</p>
        </div>
      </div>
      <nav className="flex-1 overflow-y-auto p-3 space-y-0.5">
        {navItems.map((item) => (
          <NavLink key={item.to} to={item.to} onClick={() => setSidebarOpen(false)}
            className={({ isActive }) => clsx("nav-item", isActive && "nav-item-active")}>
            {item.highlight
              ? <><SparklesSolid className="w-5 h-5 text-primary-500 flex-shrink-0" /><span className="bg-gradient-to-r from-primary-600 to-purple-600 bg-clip-text text-transparent font-semibold">{item.label}</span></>
              : <><item.icon className="w-5 h-5 flex-shrink-0" /><span>{item.label}</span></>}
          </NavLink>
        ))}
      </nav>
      <div className="p-3 border-t border-slate-100 space-y-1">
        <NavLink to="/settings" className={({ isActive }) => clsx("nav-item", isActive && "nav-item-active")}><Cog6ToothIcon className="w-5 h-5" /><span>Settings</span></NavLink>
        <NavLink to="/profile"  className={({ isActive }) => clsx("nav-item", isActive && "nav-item-active")}><UserCircleIcon className="w-5 h-5" /><span>Profile</span></NavLink>
        <button onClick={handleLogout} className="nav-item w-full text-red-500 hover:bg-red-50 hover:text-red-600"><ArrowRightOnRectangleIcon className="w-5 h-5" /><span>Logout</span></button>
        <div className="px-3 py-2 mt-1 bg-slate-50 rounded-lg">
          <p className="text-xs font-semibold text-slate-800 truncate">{user?.email}</p>
          <p className="text-xs text-slate-400 capitalize">{user?.role?.replace("_", " ")}</p>
        </div>
      </div>
    </aside>
  );

  return (
    <div className="flex h-screen overflow-hidden bg-slate-50">
      <div className="hidden md:flex flex-shrink-0"><SidebarContent /></div>
      {sidebarOpen && (
        <div className="fixed inset-0 z-50 md:hidden flex">
          <div className="fixed inset-0 bg-black/40" onClick={() => setSidebarOpen(false)} />
          <div className="relative z-10"><SidebarContent /></div>
        </div>
      )}
      <div className="flex-1 flex flex-col min-w-0 overflow-hidden">
        <header className="bg-white border-b border-slate-200 px-4 py-3 flex items-center justify-between flex-shrink-0">
          <button className="md:hidden p-1.5 rounded-lg hover:bg-slate-100" onClick={() => setSidebarOpen(true)}><Bars3Icon className="w-5 h-5" /></button>
          <div className="hidden md:block" />
          <div className="flex items-center gap-2">
            <button className="relative p-2 rounded-lg hover:bg-slate-100"><BellIcon className="w-5 h-5 text-slate-600" /><span className="absolute top-1 right-1 w-2 h-2 bg-primary-500 rounded-full" /></button>
            <div className="w-8 h-8 bg-gradient-to-br from-primary-400 to-purple-500 rounded-full flex items-center justify-center text-white text-xs font-bold">{(user?.email || "U")[0].toUpperCase()}</div>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-4 md:p-6"><Outlet /></main>
      </div>
    </div>
  );
}
